import React from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css"; // Import styles

const Navbar = () => {
  return (
    <nav className="navbar">
      <div className="navbar-logo">
      <Link to="home" smooth={true} duration={500}>
        <img src="./images/logo.png"  />
        </Link>
      </div>
      <ul className="navbar-links">
      {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
  <li key={section}>
    <Link 
      to={section.toLowerCase().replace(/\s+/g, "-")} // Convert to lowercase and replace spaces with dashes
      smooth={true} 
      duration={500} 
      activeClass="active"
    >
      {section}
    </Link>
  </li>
))}

      </ul>
    </nav>
  );
};

export default Navbar;
